import { Element, Component, h, Prop, Listen, AttachInternals, Method } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';

@Component({
  tag: 'wdpr-button-group',
  shadow: true,
  formAssociated: true,
})
export class WdprButtonGroup {
  private _observer?: MutationObserver;
  private _buttons: HTMLWdprButtonElement[] = [];
  private _pressedSet: Set<HTMLWdprButtonElement> = new Set();
  private _slot!: HTMLSlotElement;

  @Element() el!: HTMLElement;

  @Prop() layout: 'wrapped' | 'horizontal-scroll' = 'wrapped';
  @Prop() name?: string;

  @Prop({ attribute: 'a11y-label' }) a11yLabel: string = '';

  @AttachInternals()
  internals: ElementInternals;

  @Listen('keydown', { capture: true })
  handleKeyDown(event: KeyboardEvent) {
    if (event.key !== KEYBOARD_KEYS.ARROW_RIGHT && event.key !== KEYBOARD_KEYS.ARROW_DOWN && event.key !== KEYBOARD_KEYS.ARROW_LEFT && event.key !== KEYBOARD_KEYS.ARROW_UP) return;

    // Find the nearest wdpr-button ancestor for the actual event target
    const origin = (event.target as HTMLElement)?.closest?.('wdpr-button') as HTMLWdprButtonElement | null;
    if (!origin) return;
    if (!this._buttons.includes(origin)) return;

    const currentIndex = this._buttons.indexOf(origin);
    let nextIndex: number | null = null;

    if (event.key === KEYBOARD_KEYS.ARROW_RIGHT || event.key === KEYBOARD_KEYS.ARROW_DOWN) {
      nextIndex = (currentIndex + 1) % this._buttons.length;
    }

    if (event.key === KEYBOARD_KEYS.ARROW_LEFT || event.key === KEYBOARD_KEYS.ARROW_UP) {
      nextIndex = (currentIndex - 1 + this._buttons.length) % this._buttons.length;
    }

    event.preventDefault();
    const nextButton = this._buttons[nextIndex!]?.shadowRoot?.querySelector('button') as HTMLButtonElement | null;
    nextButton?.focus();
  }

  @Listen('wdprClick')
  handleButtonClick(event: CustomEvent<boolean>) {
    this._handleButtonToggle(event);
    this._syncButtonsFromDom();
  }

  @Listen('formreset')
  handleFormReset() {
    this._updateFormValue();
  }

  @Method()
  async refreshInternals() {
    this._updateFormValue();
  }

  componentDidLoad() {
    this._initializeObserver();
    this._syncButtonsFromDom();
  }

  disconnectedCallback() {
    this._observer?.disconnect();
  }

  private _initializeObserver() {
    this._observer = new MutationObserver(() => {
      this._syncButtonsFromDom();
    });

    this._observer.observe(this.el, {
      childList: true,
      subtree: true,
    });
  }

  private _getFormValue(): string {
    return String(this._pressedButtons[0]?.value || '');
  }

  private _updateFormValue() {
    const hasButtons = this._buttons.length > 0;

    if (!hasButtons) {
      this.internals?.setFormValue?.(null);

      return;
    }

    queueMicrotask(() => {
      if (this.internals && this.name) {
        this.internals?.setFormValue?.(this._getFormValue());
      }
    });
    this._updateValidity();
  }

  private _updateValidity() {
    this.internals?.setValidity?.({});
  }

  private _setPressed(button: HTMLWdprButtonElement, pressed: boolean) {
    if (pressed) {
      this._pressedSet.add(button);
      button.setAttribute('data-pressed', 'true');
      button.setAttribute('aria-pressed', 'true');

      return;
    }

    this._pressedSet.delete(button);
    button.removeAttribute('data-pressed');
    button.setAttribute('aria-pressed', 'false');
  }

  private _handleButtonToggle = (event: CustomEvent<boolean>) => {
    const toggledButton = (event.target as HTMLElement)?.closest?.('wdpr-button') as HTMLWdprButtonElement | null;
    if (!toggledButton) return;
    if (!this._buttons.includes(toggledButton)) return;

    this._buttons.forEach(button => {
      if (button !== toggledButton) this._setPressed(button, false);
    });

    this._setPressed(toggledButton, true);
    this._updateFormValue();
  };

  private _syncButtonsFromDom() {
    if (this._slot) {
      const assigned = this._slot.assignedElements({ flatten: true }) as HTMLElement[];

      // Show only wdpr-button elements and hide the rest
      this._buttons = assigned.filter(element => element.tagName.toLowerCase() === 'wdpr-button') as HTMLWdprButtonElement[];
      assigned.forEach((element: HTMLElement) => {
        if (element.tagName.toLowerCase() === 'wdpr-button') element.style.display = '';
        else element.style.display = 'none';
      });
    } else {
      this._buttons = Array.from(this.el.querySelectorAll('wdpr-button')) as HTMLWdprButtonElement[];
    }

    this._updateFormValue();
  }

  private get _pressedButtons(): HTMLWdprButtonElement[] {
    return Array.from(this._pressedSet.values());
  }

  private get containerClass(): string {
    const layoutClasses = this.layout === 'horizontal-scroll' ? 'flex-nowrap w-max px-100' : 'flex-wrap';

    return customTwMerge('flex gap-100 py-300', layoutClasses);
  }

  render() {
    if (this.layout === 'horizontal-scroll') {
      return (
        <wdpr-scrollbar orientation="horizontal" class="w-full block">
          <div part="button-group-container" class={this.containerClass} role="group" aria-label={this.a11yLabel}>
            <slot ref={el => (this._slot = el as HTMLSlotElement)} onSlotchange={() => this._syncButtonsFromDom()} />
          </div>
        </wdpr-scrollbar>
      );
    }

    return (
      <div part="button-group-container" class={this.containerClass} role="group" aria-label={this.a11yLabel}>
        <slot ref={el => (this._slot = el as HTMLSlotElement)} onSlotchange={() => this._syncButtonsFromDom()} />
      </div>
    );
  }
}
